using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService(ILogger<ModelTrainingService> logger)
{
    private const int Seed = 42;

    public string TrainAndSave(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: Seed);

        // Load data
        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Split into train/test sets (80/20)
        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: Seed);

        // Build the pipeline: featurize text + numeric, then classify
        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Train
        logger.LogInformation("Training model on {Path}...", dataPath);
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on held-out test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        var report = $"""
            ===== Model Evaluation Metrics =====
            Macro Accuracy:    {metrics.MacroAccuracy:F4}
            Micro Accuracy:    {metrics.MicroAccuracy:F4}
            Log Loss:          {metrics.LogLoss:F4}
            Log Loss Reduction:{metrics.LogLossReduction:F4}
            ====================================
            Per-class metrics:
            {metrics.ConfusionMatrix.GetFormattedConfusionTable()}
            """;

        logger.LogInformation("{Metrics}", report);

        // Save model
        mlContext.Model.Save(model, data.Schema, modelPath);
        logger.LogInformation("Model saved to {ModelPath}", modelPath);

        return report;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController(
    PredictionEnginePool<TicketInput, TicketPrediction> predictionPool) : ControllerBase
{
    /// <summary>Predict the category for a support ticket.</summary>
    [HttpPost("predict")]
    public ActionResult<TicketResponse> Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = predictionPool.Predict(input);

        var labels = new[] { "Billing", "General", "Technical" };
        var confidence = labels
            .Zip(prediction.Score)
            .ToDictionary(pair => pair.First, pair => pair.Second);

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence,
        });
    }
}

[ApiController]
[Route("api/[controller]")]
public class ModelController(
    ModelTrainingService trainingService,
    IWebHostEnvironment env) : ControllerBase
{
    /// <summary>Retrain the model from the CSV data.</summary>
    [HttpPost("train")]
    public ActionResult<string> Train()
    {
        var dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        var modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");

        var report = trainingService.TrainAndSave(dataPath, modelPath);
        return Ok(report);
    }
}

